-- Simple Focus colorscheme for Neovim
-- Auto-generated by convert_theme.py (VSCodium theme by ncodefun + user overrides)

vim.cmd("highlight clear")
if vim.fn.exists("syntax_on") == 1 then
  vim.cmd("syntax reset")
end
